import React, { useEffect, useState } from 'react';
import { BrowserRouter, Routes, Route, Navigate, useLocation } from 'react-router-dom';
import { AnimatePresence, motion } from 'framer-motion';
import { Sidebar } from './components/layout/Sidebar';
import { MobileTabBar } from './components/layout/MobileTabBar';
import { Dashboard } from './pages/Dashboard';
import { ExamTracker } from './pages/ExamTracker';
import { WeeklyPlanner } from './pages/WeeklyPlanner';
import { Objetivos } from './pages/Objetivos';
import { Timeline } from './pages/Timeline';
import { Estadisticas } from './pages/Estadisticas';
import { ModoExamen } from './pages/ModoExamen';

import { useExamStore } from './store/useExamStore';
import { usePlannerStore } from './store/usePlannerStore';
import { useHabitStore } from './store/useHabitStore';
import { useGoalStore } from './store/useGoalStore';
import { SEED_EXAMS, SEED_BLOCKS, SEED_HABITS, SEED_GOALS } from './lib/seed';

import { ThemeProvider } from './lib/theme';
import { ToastProvider, useToast } from './components/ui/Toast';
import { decodeShareLink } from './lib/share';
import { scheduleExamReminders } from './lib/notifications';
import { Modal } from './components/ui/Modal';
import { Button } from './components/ui/Button';
import { formatDateES } from './lib/utils';
import type { Exam } from './types';

// ─── App Level Interceptor (Import & Notifs logic) ─────────────────────────────
const AppProvidersAndLogic = ({ children }: { children: React.ReactNode }) => {
  const { exams, addExam } = useExamStore();
  const { showToast } = useToast();

  // 1. URL Import Interceptor
  const [importExam, setImportExam] = useState<Partial<Exam> | null>(null);

  useEffect(() => {
    const url = new URL(window.location.href);
    const imp = url.searchParams.get('import');
    if (imp) {
      const decoded = decodeShareLink(imp);
      if (decoded) setTimeout(() => setImportExam(decoded), 0);
      // Clean URL silently
      window.history.replaceState({}, document.title, window.location.pathname);
    }
  }, []);

  const handleImport = () => {
    if (!importExam) return;
    addExam({ ...importExam, status: 'pendiente' } as any);
    showToast('Examen importado con éxito');
    setImportExam(null);
  };

  // 2. Notification Scheduler
  useEffect(() => {
    scheduleExamReminders(exams);
  }, [exams]);

  // 3. Seed Logic
  useEffect(() => {
    const hasExams = useExamStore.getState().exams.length > 0;
    const hasBlocks = usePlannerStore.getState().blocks.length > 0;
    const hasHabits = useHabitStore.getState().habits.length > 0;
    const hasGoals = useGoalStore.getState().goals.length > 0;
    if (!hasExams && !hasBlocks && !hasHabits && !hasGoals) {
      useExamStore.setState({ exams: SEED_EXAMS });
      usePlannerStore.setState({ blocks: SEED_BLOCKS });
      useHabitStore.setState({ habits: SEED_HABITS });
      useGoalStore.setState({ goals: SEED_GOALS });
    }
  }, []);

  return (
    <>
      {children}
      <Modal open={!!importExam} onClose={() => setImportExam(null)} title="Tu compañero compartió un examen">
        {importExam && (
          <div className="flex flex-col gap-4">
            <div className="bg-elevated border border-border rounded-card p-4">
              <p className="text-text-primary font-semibold text-lg">{importExam.subject}</p>
              <div className="flex items-center gap-2 mt-2 text-sm text-text-muted capitalize">
                <span className="bg-surface px-2 py-0.5 rounded border border-border">{importExam.type}</span>
                {importExam.date && <span>— {formatDateES(importExam.date)}</span>}
              </div>
            </div>
            <div className="flex justify-end gap-3 mt-2">
              <Button onClick={() => setImportExam(null)} variant="ghost">Ignorar</Button>
              <Button onClick={handleImport} variant="primary" className="!bg-amber !text-[#17130b]">Importar examen</Button>
            </div>
          </div>
        )}
      </Modal>
    </>
  );
};

// ─── Route Animations ─────────────────────────────────────────────────────────
const titles: Record<string, string> = {
  '/dashboard': 'Dashboard | Faculty OS',
  '/examenes': 'Exámenes | Faculty OS',
  '/planner': 'Planificador | Faculty OS',
  '/objetivos': 'Objetivos | Faculty OS',
  '/timeline': 'Timeline | Faculty OS',
  '/estadisticas': 'Estadísticas | Faculty OS',
};

const AnimatedRoutes = () => {
  const location = useLocation();

  useEffect(() => {
    document.title = titles[location.pathname] || 'Faculty OS';
  }, [location]);

  return (
    <AnimatePresence mode="wait">
      <motion.div
        key={location.pathname}
        initial={{ opacity: 0, y: 10 }}
        animate={{ opacity: 1, y: 0 }}
        exit={{ opacity: 0, y: -10 }}
        transition={{ duration: 0.2, ease: 'easeOut' }}
        className="h-full"
      >
        <Routes location={location}>
          <Route path="/" element={<Navigate to="/dashboard" replace />} />
          <Route path="/dashboard" element={<Dashboard />} />
          <Route path="/examenes" element={<ExamTracker />} />
          <Route path="/planner" element={<WeeklyPlanner />} />
          <Route path="/objetivos" element={<Objetivos />} />
          <Route path="/timeline" element={<Timeline />} />
          <Route path="/estadisticas" element={<Estadisticas />} />
        </Routes>
      </motion.div>
    </AnimatePresence>
  );
};

const MainLayout = () => {
  return (
    <div className="flex h-screen overflow-hidden bg-base text-text-primary">
      <Sidebar />
      <div className="flex flex-col flex-1 min-w-0 overflow-hidden relative">
        <div className="absolute top-0 left-0 right-0 h-10 bg-gradient-to-b from-base to-transparent z-10 pointer-events-none" />
        <main className="flex-1 overflow-y-auto pb-24 md:pb-0 px-4 md:px-8 xl:px-12 pt-8 scroll-smooth">
          <AnimatedRoutes />
        </main>
      </div>
      <MobileTabBar />
    </div>
  );
};

export default function App() {
  return (
    <ThemeProvider>
      <ToastProvider>
        <BrowserRouter>
          <AppProvidersAndLogic>
            <Routes>
              <Route path="/modo-examen/:examId" element={<ModoExamen />} />
              <Route path="*" element={<MainLayout />} />
            </Routes>
          </AppProvidersAndLogic>
        </BrowserRouter>
      </ToastProvider>
    </ThemeProvider>
  );
}

import React, { createContext, useContext, useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

interface ToastContextType {
  showToast: (message: string) => void;
}

const ToastContext = createContext<ToastContextType | undefined>(undefined);

export const ToastProvider = ({ children }: { children: React.ReactNode }) => {
  const [toast, setToast] = useState<{ id: number, message: string } | null>(null);

  const showToast = (message: string) => {
    const id = Date.now();
    setToast({ id, message });
  };

  useEffect(() => {
    if (toast) {
      const t = setTimeout(() => setToast(null), 3000);
      return () => clearTimeout(t);
    }
  }, [toast]);

  return (
    <ToastContext.Provider value={{ showToast }}>
      {children}
      <AnimatePresence>
        {toast && (
          <motion.div
            key={toast.id}
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: 10 }}
            className="fixed bottom-6 left-1/2 -translate-x-1/2 z-50 bg-elevated border border-border shadow-2xl rounded-[10px] px-4 py-3 text-sm font-medium text-text-primary text-center min-w-[200px]"
          >
            {toast.message}
          </motion.div>
        )}
      </AnimatePresence>
    </ToastContext.Provider>
  );
};

export const useToast = () => {
  const ctx = useContext(ToastContext);
  if (!ctx) throw new Error('useToast must be within ToastProvider');
  return ctx;
};

import type { Exam } from '../types';

export async function requestNotificationPermission(): Promise<boolean> {
  if (!('Notification' in window)) return false;
  if (Notification.permission === 'granted') return true;
  if (Notification.permission === 'denied') return false;

  const perm = await Notification.requestPermission();
  return perm === 'granted';
}

export function scheduleExamReminders(exams: Exam[]): void {
  if (!('Notification' in window) || Notification.permission !== 'granted') return;

  // Clear any previously scheduled timeouts (for SPA re-renders)
  if ((window as any)._fosTimeouts) {
    (window as any)._fosTimeouts.forEach((t: number) => clearTimeout(t));
  }
  (window as any)._fosTimeouts = [];

  const storedNotifs: string[] = JSON.parse(localStorage.getItem('fos-notif-ids') || '[]');
  const now = new Date().getTime();

  exams.forEach(exam => {
    if (exam.status !== 'pendiente') return;
    const examDate = new Date(exam.date).getTime();

    // Notifications we want to trigger:
    const checks = [
      { daysLeft: 7, title: `📚 ${exam.subject}`, body: `${exam.type} en 7 días. Hora de arrancar.` },
      { daysLeft: 3, title: `⚠️ ${exam.subject}`, body: `${exam.type} en 3 días. ¿Cómo va el repaso?` },
      { daysLeft: 1, title: `🔴 Mañana es ${exam.type} de ${exam.subject}`, body: `Última noche.` },
    ];

    checks.forEach(({ daysLeft, title, body }) => {
      const targetTime = examDate - (daysLeft * 24 * 60 * 60 * 1000);
      const notifId = `exam-${exam.id}-${daysLeft}d`;

      // If the target time is in the future, and we haven't already sent/scheduled it:
      if (targetTime > now && !storedNotifs.includes(notifId)) {
        const delay = targetTime - now;

        // Browsers limit setTimeout maximum to about 24 days (2147483647 ms)
        if (delay > 2147483647) return; 

        const timeoutId = setTimeout(() => {
          new Notification(title, {
            body,
            icon: '/favicon.ico',
            badge: '/favicon.ico',
            tag: notifId
          });

          const currentNotifs = JSON.parse(localStorage.getItem('fos-notif-ids') || '[]');
          localStorage.setItem('fos-notif-ids', JSON.stringify([...currentNotifs, notifId]));
        }, delay);

        (window as any)._fosTimeouts.push(timeoutId);
      }
    });
  });
}

export function clearAllReminders(): void {
  if ((window as any)._fosTimeouts) {
    (window as any)._fosTimeouts.forEach((t: number) => clearTimeout(t));
    (window as any)._fosTimeouts = [];
  }
}

import React, { createContext, useContext, useEffect, useState } from 'react';

type Theme = 'light' | 'dark';

interface ThemeContextType {
  theme: Theme;
  toggleTheme: () => void;
}

const ThemeContext = createContext<ThemeContextType | undefined>(undefined);

export const ThemeProvider = ({ children }: { children: React.ReactNode }) => {
  const [theme, setTheme] = useState<Theme>(() => {
    const stored = localStorage.getItem('fos-theme') as Theme | null;
    if (stored) return stored;
    return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
  });

  useEffect(() => {
    document.documentElement.setAttribute('data-theme', theme);
    localStorage.setItem('fos-theme', theme);
  }, [theme]);

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');

  return (
    <ThemeContext.Provider value={{ theme, toggleTheme }}>
      {children}
    </ThemeContext.Provider>
  );
};

export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (!context) throw new Error('useTheme must be used within ThemeProvider');
  return context;
};

import React, { useMemo } from 'react';
import { useExamStore } from '../store/useExamStore';
import { usePlannerStore } from '../store/usePlannerStore';
import { useHabitStore } from '../store/useHabitStore';
import { formatDateES, cn } from '../lib/utils';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, BarChart, Bar, Cell } from 'recharts';

const CustomTooltipLine = ({ active, payload }: any) => {
  if (active && payload && payload.length) {
    const d = payload[0].payload;
    return (
      <div className="bg-elevated border border-border p-3 rounded-card shadow-xl">
        <p className="font-semibold text-text-primary text-sm mb-1">{d.subject}</p>
        <p className="text-xs text-text-muted">{d.fullDate}</p>
        <p className="text-amber font-bold text-lg mt-1">{d.grade}</p>
      </div>
    );
  }
  return null;
};

export const Estadisticas = () => {
  const { exams } = useExamStore();
  const { blocks } = usePlannerStore();
  const { habits } = useHabitStore();

  const statsData = useMemo(() => {
    // Top 4 stats
    const subjectsCursando = new Set(exams.filter(e => e.status === 'pendiente').map(e => e.subject)).size;
    const gradedExams = exams.filter(e => typeof e.grade === 'number');
    const promedio = gradedExams.length ? (gradedExams.reduce((a, b) => a + b.grade!, 0) / gradedExams.length).toFixed(2) : '-';

    const passed = exams.filter(e => e.status === 'aprobado').length;
    const failed = exams.filter(e => e.status === 'desaprobado').length;
    const tasaAprobacion = passed + failed > 0 ? Math.round((passed / (passed + failed)) * 100) : 0;

    const studyHoursPerWeek = blocks.filter(b => b.category === 'estudio').reduce((acc, b) => acc + (b.endHour - b.startHour), 0);
    const studyHoursMonth = Math.round(studyHoursPerWeek * 4.33);

    // Line Chart: Evolución de notas
    const lineChartData = exams
      .filter(e => typeof e.grade === 'number')
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime())
      .map(e => ({
        name: formatDateES(e.date).split(',')[0], // just day and month
        subject: e.subject,
        grade: e.grade,
        fullDate: formatDateES(e.date),
      }));

    // Generate colors for subjects
    const subjects = Array.from(new Set(exams.map(e => e.subject)));
    const subjectColors = subjects.reduce((acc, sub, i) => {
      const colors = ['#f59e0b', '#3b82f6', '#10b981', '#ef4444', '#8b5cf6', '#ec4899'];
      acc[sub] = colors[i % colors.length];
      return acc;
    }, {} as Record<string, string>);

    // Bar Chart: Distribucion por materia
    const distData = subjects.map(sub => {
      const subGrades = exams.filter(e => e.subject === sub && typeof e.grade === 'number');
      const avg = subGrades.length ? subGrades.reduce((a, b) => a + b.grade!, 0) / subGrades.length : 0;
      return { subject: sub, avg };
    }).filter(d => d.avg > 0).sort((a, b) => b.avg - a.avg);

    // Bar Chart: Carga semanal historica (mocked from current week)
    const weekLoad = blocks.filter(b => b.category === 'estudio' || b.category === 'facultad').reduce((acc, b) => acc + (b.endHour - b.startHour), 0);
    const weeklyData = Array.from({ length: 8 }).map((_, i) => ({
      name: `Sem ${10 + i}`,
      hours: weekLoad > 0 ? Math.max(0, weekLoad + ((((i * 7) % 11) / 10) * 10 - 5)) : 0, // slight variation
    }));

    return { subjectsCursando, promedio, tasaAprobacion, studyHoursMonth, lineChartData, subjectColors, distData, weeklyData };
  }, [exams, blocks]);



  return (
    <div className="space-y-8 pb-20">
      <header>
        <h1 className="text-2xl font-semibold tracking-tight text-text-primary">Estadísticas</h1>
        <p className="text-text-muted mt-1 text-[13px]">Resumen histórico de tu rendimiento</p>
      </header>

      {/* 4 Generic Metrics */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {[
          { label: 'Materias cursando', val: statsData.subjectsCursando },
          { label: 'Promedio general', val: statsData.promedio },
          { label: 'Tasa de aprobación', val: statsData.tasaAprobacion + '%' },
          { label: 'Horas (mensual)', val: statsData.studyHoursMonth + 'h' },
        ].map(s => (
          <div key={s.label} className="bg-elevated border border-border p-4 rounded-card flex flex-col gap-1">
            <span className="text-xs text-text-muted uppercase font-medium">{s.label}</span>
            <span className="text-2xl font-bold text-text-primary mt-auto">{s.val}</span>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">

        {/* Line Chart */}
        <div className="bg-elevated border border-border p-5 rounded-xl flex flex-col min-h-[300px]">
          <h3 className="text-sm font-semibold tracking-[-0.2px] text-text-primary mb-6">Evolución de notas</h3>
          {statsData.lineChartData.length < 2 ? (
            <div className="flex-1 flex items-center justify-center text-text-muted text-sm">
              Cargá más notas para ver la evolución
            </div>
          ) : (
            <div className="flex-1 min-h-[250px] w-full">
              <ResponsiveContainer width="100%" height="100%">
                <LineChart data={statsData.lineChartData} margin={{ top: 5, right: 10, left: -20, bottom: 0 }}>
                  <CartesianGrid strokeDasharray="3 3" stroke="var(--border)" vertical={false} />
                  <XAxis dataKey="name" stroke="var(--text-muted)" fontSize={11} tickLine={false} axisLine={false} dy={10} />
                  <YAxis domain={['auto', 10]} stroke="var(--text-muted)" fontSize={11} tickLine={false} axisLine={false} dx={-10} />
                  <Tooltip content={<CustomTooltipLine />} cursor={{ stroke: 'var(--border)', strokeWidth: 1, strokeDasharray: '4 4' }} />
                  <Line type="monotone" dataKey="grade" stroke="var(--amber)" strokeWidth={3} dot={{ stroke: 'var(--amber)', strokeWidth: 2, r: 4, fill: 'var(--bg-elevated)' }} activeDot={{ r: 6, fill: 'var(--amber)' }} />
                </LineChart>
              </ResponsiveContainer>
            </div>
          )}
        </div>

        {/* Bar Chart Dist */}
        <div className="bg-elevated border border-border p-5 rounded-xl flex flex-col min-h-[300px]">
          <h3 className="text-sm font-semibold tracking-[-0.2px] text-text-primary mb-6">Distribución por materia</h3>
          {statsData.distData.length === 0 ? (
            <div className="flex-1 flex items-center justify-center text-text-muted text-sm">
              Sin datos suficientes
            </div>
          ) : (
            <div className="flex-1 min-h-[250px] w-full">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={statsData.distData} layout="vertical" margin={{ top: 5, right: 30, left: 10, bottom: 0 }}>
                  <CartesianGrid strokeDasharray="3 3" stroke="var(--border)" horizontal={false} />
                  <XAxis type="number" domain={[0, 10]} stroke="var(--text-muted)" fontSize={11} tickLine={false} axisLine={false} />
                  <YAxis type="category" dataKey="subject" stroke="var(--text-primary)" fontSize={11} tickLine={false} axisLine={false} width={120} tickFormatter={(val) => val.length > 15 ? val.substring(0, 15) + '...' : val} />
                  <Tooltip cursor={{ fill: 'var(--border)', opacity: 0.2 }} content={({ active, payload }) => {
                    if (active && payload && payload.length) {
                      return <div className="bg-elevated border border-border px-3 py-2 rounded shadow-md text-xs font-bold text-text-primary">{payload[0].payload.subject}: {(payload[0].value as number).toFixed(2)}</div>
                    } return null;
                  }} />
                  <Bar dataKey="avg" radius={[0, 4, 4, 0]} barSize={24}>
                    {statsData.distData.map((entry, index) => {
                      const c = entry.avg >= 7 ? 'var(--green)' : entry.avg >= 5 ? 'var(--amber)' : 'var(--red)';
                      return <Cell key={`cell-${index}`} fill={c} />;
                    })}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            </div>
          )}
        </div>

        {/* Carga Semanal Histórica */}
        <div className="bg-elevated border border-border p-5 rounded-xl flex flex-col min-h-[300px]">
          <h3 className="text-sm font-semibold tracking-[-0.2px] text-text-primary mb-6">Carga Semanal Histórica</h3>
          <div className="flex-1 min-h-[250px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={statsData.weeklyData} margin={{ top: 5, right: 10, left: -20, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" stroke="var(--border)" vertical={false} />
                <XAxis dataKey="name" stroke="var(--text-muted)" fontSize={11} tickLine={false} axisLine={false} dy={10} />
                <YAxis stroke="var(--text-muted)" fontSize={11} tickLine={false} axisLine={false} dx={-10} />
                <Tooltip cursor={{ fill: 'var(--border)', opacity: 0.2 }} content={({ active, payload }) => {
                  if (active && payload && payload.length) {
                    return <div className="bg-elevated border border-border px-2 py-1 rounded shadow-md text-xs font-bold text-text-primary">{(payload[0].value as number).toFixed(1)} hs</div>
                  } return null;
                }} />
                <Bar dataKey="hours" radius={[3, 3, 0, 0]} barSize={28}>
                  {statsData.weeklyData.map((entry, index) => {
                    const c = entry.hours <= 35 ? 'var(--green)' : entry.hours <= 40 ? 'var(--amber)' : 'var(--red)';
                    return <Cell key={`cell-${index}`} fill={c} />;
                  })}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Racha de Hábitos */}
        <div className="bg-elevated border border-border p-5 rounded-xl flex flex-col">
          <h3 className="text-sm font-semibold tracking-[-0.2px] text-text-primary mb-6">Racha de Hábitos (Últimos 30 días)</h3>
          <div className="flex flex-col gap-5">
            {habits.map(h => {
              // Mock 30 days by repeating the 7 days array
              const mock30 = Array.from({ length: 30 }).map((_, i) => h.completedDays[i % 7]);
              let currentStreak = 0;
              for (let i = mock30.length - 1; i >= 0; i--) {
                if (mock30[i]) currentStreak++; else break;
              }
              const bestStreak = mock30.reduce((acc, val) => {
                if (val) { acc.curr++; acc.max = Math.max(acc.max, acc.curr); }
                else { acc.curr = 0; }
                return acc;
              }, { curr: 0, max: 0 }).max;

              return (
                <div key={h.id} className="flex flex-col gap-2">
                  <div className="flex justify-between items-center text-xs">
                    <span className="font-semibold text-text-primary">{h.label}</span>
                    <span className="text-text-muted">Actual: <strong className="text-text-primary">{currentStreak}</strong> · Mejor: <strong className="text-text-primary">{bestStreak}</strong></span>
                  </div>
                  <div className="flex gap-1 overflow-visible w-full">
                    {mock30.map((done, i) => (
                      <div 
                        key={i} 
                        className={cn("h-3 flex-1 rounded-sm border", done ? "border-transparent" : "bg-base border-border opacity-50")}
                        style={done ? { backgroundColor: h.color } : {}}
                        title={done ? 'Completado' : 'No completado'}
                      />
                    ))}
                  </div>
                </div>
              );
            })}
            {habits.length === 0 && <p className="text-text-muted text-sm text-center py-4">Agregá hábitos en el Dashboard</p>}
          </div>
        </div>

      </div>
    </div>
  );
};

