  const submit = (e: React.FormEvent) => { e.preventDefault(); onSave(f as any); };

  return (
    <form onSubmit={submit} className="flex flex-col gap-4">
      <div>
        <label className="label mb-1.5 block">Título</label>
        <input className="input" autoFocus value={f.title} onChange={e=>setF({...f, title: e.target.value})} required />
      </div>
      <div>
        <label className="label mb-1.5 block">Categoría</label>
        <SegmentedControl options={['academico', 'personal', 'emprendimiento']} value={f.category} onChange={v => setF({...f, category: v as any})} />
