// ─── Objetivos Page ────────────────────────────────────────────────────────────
export const Objetivos: React.FC = () => {
  const { goals, addGoal, updateGoal, deleteGoal } = useGoalStore();
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<Goal | null>(null);
  const [activeCategory, setActiveCategory] = useState<Goal['category']>('academico');

  const catColors: Record<string, string> = { academico: '#f59e0b', personal: '#fb923c', emprendimiento: '#d4a86a' };

  const handleSave = (d: Omit<Goal, 'id'>) => {
    if (editing) updateGoal(editing.id, d);
    else addGoal(d);
    setModalOpen(false);
  };

  const getSorted = (cat: Goal['category']) => {
    return goals.filter(g => g.category === cat).sort((a,b) => {
      if (a.progress === 100 && b.progress < 100) return 1;
      if (a.progress < 100 && b.progress === 100) return -1;
      if (!a.deadline && b.deadline) return 1;
      if (a.deadline && !b.deadline) return -1;
      if (a.deadline && b.deadline) return new Date(a.deadline).getTime() - new Date(b.deadline).getTime();
      return 0; // fallback to creation order if tracked, otherwise store order is fine
    });
  };

  const cats: Goal['category'][] = ['academico', 'personal', 'emprendimiento'];

  return (
    <div className="max-w-7xl mx-auto h-full flex flex-col pb-6">
      <header className="mb-6 flex flex-col md:flex-row md:items-end justify-between gap-4 shrink-0 px-1">
        <div>
          <h1 className="text-2xl font-semibold tracking-tight text-text-primary flex items-center gap-2 mb-1">
            <Target size={22} className="text-amber" /> Mis Objetivos
          </h1>
        </div>
      </header>

      <div className="flex-1 min-h-0 flex flex-col md:flex-row gap-6 md:gap-4 overflow-y-auto md:overflow-visible pr-1">
        {cats.map(cat => {
          const catGoals = getSorted(cat);
          return (
            <div key={cat} className="flex-1 flex flex-col gap-3 min-w-0">
              <div className="flex items-center justify-between px-2 shrink-0">
                <div className="flex items-center gap-2">
                  <h2 className="text-[11px] font-bold uppercase tracking-widest text-text-muted">{cat}</h2>
                  <span className="bg-elevated text-text-secondary text-[10px] font-bold px-1.5 py-0.5 rounded border border-border">{catGoals.length}</span>
                </div>
                <button onClick={() => { setActiveCategory(cat); setEditing(null); setModalOpen(true); }} className="text-[11px] font-semibold text-text-secondary hover:text-amber transition-colors">+ Agregar</button>
              </div>

              {catGoals.length === 0 ? (
                <div className="border border-dashed border-border/50 rounded-[14px] flex flex-col items-center justify-center py-10 opacity-70 hover:opacity-100 transition-opacity bg-surface/30 cursor-pointer" onClick={() => { setActiveCategory(cat); setEditing(null); setModalOpen(true); }}>
                  <Plus size={20} className="text-text-muted mb-2" />
                  <span className="text-[12px] font-medium text-text-secondary">Agregar objetivo</span>
                </div>
              ) : (
                <div className="flex flex-col gap-3 md:overflow-y-auto md:pr-1 pb-4">
                  {catGoals.map(g => {
                     const color = catColors[g.category];
                     const isCompleted = g.progress === 100;
                     const isUrgent = g.deadline && daysUntil(g.deadline) < 7 && !isCompleted;

                     return (
                       <motion.div layout key={g.id} className={cn("bg-surface border border-border rounded-[14px] p-4 group relative flex flex-col gap-3", isCompleted && "opacity-60 grayscale hover:grayscale-0 transition-all")}>
                          <div className="absolute top-3 right-3 opacity-0 group-hover:opacity-100 transition-opacity">
                            <button onClick={()=>deleteGoal(g.id)} className="p-1 text-text-muted hover:text-red"><Trash2 size={13}/></button>
                          </div>

                          <div className="flex flex-col gap-1.5 pr-6">
                            <div className="flex items-center gap-2">
                              <span className="w-2 h-2 rounded-full shadow-sm" style={{ backgroundColor: color }} />
                              {g.deadline && <span className={cn("text-[11px] font-medium flex items-center gap-1", isUrgent ? "text-red" : "text-text-muted")}><Clock size={10} strokeWidth={2.5}/> Vence {formatDateES(g.deadline).slice(0,6)}</span>}
                            </div>
                            <h3 className={cn("text-[14px] font-medium text-text-primary leading-tight", isCompleted && "line-through opacity-80")}>{g.title}</h3>
                          </div>

                          <div className="mt-auto flex flex-col gap-1">
                            <div className="flex items-center gap-3">
                              {isCompleted ? (
                                <div className="flex-1 h-1 bg-green/20 rounded-full overflow-hidden flex items-center"><div className="w-full h-full bg-green" /></div>
                              ) : (
                                <input type="range" min={0} max={100} step={5} value={g.progress} onChange={e => updateGoal(g.id, { progress: Number(e.target.value) })}
                                  className="flex-1 h-1 bg-elevated border border-border/50 rounded-full appearance-none cursor-pointer [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:w-2.5 [&::-webkit-slider-thumb]:h-2.5 [&::-webkit-slider-thumb]:rounded-full hover:[&::-webkit-slider-thumb]:scale-150 transition-all" 
                                  style={{ background: `linear-gradient(to right, ${color} ${g.progress}%, #17130b ${g.progress}%)`}}
                                />
                              )}
                            </div>
                            <div className="flex justify-end pr-1">
                              {isCompleted ? <Check size={12} strokeWidth={3} className="text-green" /> : <span className="text-[11px] font-semibold text-text-muted">{g.progress}%</span>}
                            </div>
                          </div>
                       </motion.div>
                     );
                  })}
                </div>
              )}
            </div>
          );
        })}
      </div>

      <Modal open={modalOpen} onClose={() => setModalOpen(false)} title={editing ? 'Editar Objetivo' : 'Nuevo Objetivo'} size="sm">
         <GoalForm initial={editing ?? { category: activeCategory }} onSave={handleSave} onCancel={() => setModalOpen(false)} />
      </Modal>
    </div>
  );
};

