import React, { useMemo } from 'react';
import { useExamStore } from '../store/useExamStore';
import { daysUntil, cn, formatDateES } from '../lib/utils';
import { Info } from 'lucide-react';

export const Timeline = () => {
  const { exams } = useExamStore();

  const timelineData = useMemo(() => {
    const now = new Date();
    // Cuatrimestre 1: March 1 (2) to July 31 (6)
    // Cuatrimestre 2: August 1 (7) to December 15 (11)
    const currentMonth = now.getMonth();
    const isC1 = currentMonth < 7;
    const year = now.getFullYear();

    const startDate = new Date(year, isC1 ? 2 : 7, 1);
    const endDate = new Date(year, isC1 ? 6 : 11, isC1 ? 31 : 15);

    const totalMs = endDate.getTime() - startDate.getTime();
    const totalDays = Math.round(totalMs / (1000 * 60 * 60 * 24));

    const todayMs = now.getTime() - startDate.getTime();
    const todayPercent = Math.max(0, Math.min(100, (todayMs / totalMs) * 100));

    // Filter pending exams in this semester
    let semesterExams = exams
      .filter(e => e.status === 'pendiente')
      .map(e => {
        const d = new Date(e.date);
        const percent = Math.max(0, Math.min(100, ((d.getTime() - startDate.getTime()) / totalMs) * 100));
        return { ...e, percent, d };
      })
      .filter(e => e.percent >= 0 && e.percent <= 100)
      .sort((a, b) => a.d.getTime() - b.d.getTime());

    // Stagger pills vertically
    const rows: { endPercent: number }[] = [];
    const layoutExams = semesterExams.map(ex => {
      let rowIndex = rows.findIndex(r => r.endPercent < ex.percent - 5); // 5% minimum gap
      if (rowIndex === -1) {
        rowIndex = rows.length;
        rows.push({ endPercent: ex.percent });
      } else {
        rows[rowIndex].endPercent = ex.percent;
      }
      return { ...ex, rowIndex: Math.min(rowIndex, 2) }; // Cap at 3 rows (0, 1, 2)
    });

    // Weeks
    const totalWeeks = Math.ceil(totalDays / 7);
    const weeks = Array.from({ length: totalWeeks }).map((_, i) => {
      const weekPercent = ((i * 7) / totalDays) * 100;
      // count exams in this week
      const examsInWeek = layoutExams.filter(e => e.percent >= weekPercent && e.percent < weekPercent + (7/totalDays)*100).length;
      return { number: i + 1, percent: weekPercent, examsCount: examsInWeek };
    });

    return { isC1, startDate, endDate, totalDays, todayPercent, exams: layoutExams, weeks };
  }, [exams]);

  return (
    <div className="space-y-6 pb-20">
      <header>
        <h1 className="text-2xl font-semibold tracking-tight text-text-primary">Timeline del cuatrimestre</h1>
        <p className="text-text-muted mt-1 text-[13px]">
          {timelineData.isC1 ? 'Primer' : 'Segundo'} Cuatrimestre ({timelineData.startDate.toLocaleDateString('es-AR', { month: 'long' })} - {timelineData.endDate.toLocaleDateString('es-AR', { month: 'long' })})
        </p>
      </header>

      {timelineData.exams.length === 0 ? (
        <div className="bg-elevated border border-dashed border-border p-12 rounded-card text-center text-text-muted text-sm mt-8">
          <Info className="mx-auto mb-2 opacity-50" size={24} />
          <p>Cargá tus exámenes para ver el cuatrimestre</p>
        </div>
      ) : (
        <div className="flex flex-col gap-12 mt-8">

          {/* Timeline Bar Area */}
          <div className="relative w-full pt-16 pb-12 bg-elevated border border-border rounded-xl px-4 sm:px-8">

            {/* The main bar */}
            <div className="relative h-1.5 w-full bg-border rounded-full">

              {/* Today Marker */}
              {timelineData.todayPercent > 0 && timelineData.todayPercent < 100 && (
                <div 
                  className="absolute top-0 bottom-0 w-px bg-amber border-l border-dashed border-amber/50 z-10 translate-y-[-100%] h-32"
                  style={{ left: `${timelineData.todayPercent}%` }}
                >
                  <span className="absolute -top-6 -left-3 text-[10px] font-bold text-amber bg-amber/10 px-1.5 py-0.5 rounded">Hoy</span>
                </div>
              )}

              {/* Week ticks */}
              {timelineData.weeks.map(w => (
                <div key={w.number} className="absolute top-1.5 w-px h-2 bg-text-muted/30" style={{ left: `${w.percent}%` }}>
                  <span className="absolute top-3 -translate-x-1/2 text-[9px] text-text-faint font-medium">S{w.number}</span>
                </div>
              ))}

              {/* Exams Pills */}
              {timelineData.exams.map(ex => {
                const d = daysUntil(ex.date);
                const colorClass = d < 7 ? 'bg-red text-[#17130b]' : d < 14 ? 'bg-amber text-[#17130b]' : d < 30 ? 'bg-green text-[#17130b]' : 'bg-surface text-text-primary border border-border';
                const abbrev = ex.subject.split(' ').slice(0, 2).map(s => s[0]).join('').toUpperCase() || ex.subject.substring(0,2).toUpperCase();

                return (
                  <div 
                    key={ex.id} 
                    className={cn(
                      "absolute flex items-center justify-center -translate-x-1/2 rounded-full px-2 py-0.5 text-[10px] font-bold shadow-sm whitespace-nowrap cursor-pointer z-20 group hover:z-30 transition-transform hover:scale-105",
                      colorClass
                    )}
                    style={{ left: `${ex.percent}%`, top: `${(ex.rowIndex * -28) - 14}px` }}
                  >
                    <span>{abbrev} · {ex.type}</span>

                    {/* Tooltip */}
                    <div className="absolute opacity-0 pointer-events-none group-hover:opacity-100 group-hover:pointer-events-auto bottom-full mb-1 left-1/2 -translate-x-1/2 bg-elevated text-text-primary border border-border px-3 py-2 rounded-lg shadow-xl min-w-[150px] transition-opacity">
                      <p className="font-bold text-xs truncate mb-1">{ex.subject}</p>
                      <p className="text-[10px] text-text-secondary">{formatDateES(ex.date)}</p>
                      <p className={cn("text-[10px] font-medium mt-1", d < 7 ? "text-red" : d < 14 ? "text-amber" : "text-green")}>
                        Faltan {d} días
                      </p>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>

          {/* Density Heatmap */}
          <div className="bg-elevated border border-border p-5 rounded-xl">
            <h3 className="text-xs font-semibold uppercase tracking-wider text-text-muted mb-4">Densidad de Exámenes</h3>
            <div className="flex items-end h-[60px] gap-1 px-2">
              {timelineData.weeks.map(w => {
                const height = w.examsCount === 0 ? '10%' : w.examsCount === 1 ? '50%' : '100%';
                const color = w.examsCount === 0 ? 'var(--border)' : w.examsCount === 1 ? 'var(--amber)' : 'var(--red)';
                return (
                  <div key={w.number} className="flex-1 flex flex-col items-center justify-end h-full group relative">
                    <div 
                      className="w-full max-w-[16px] rounded-t-sm transition-all"
                      style={{ height, backgroundColor: color, opacity: w.examsCount === 0 ? 0.3 : 0.9 }}
                    />
                    {/* Tooltip */}
                    {w.examsCount > 0 && (
                      <div className="absolute opacity-0 group-hover:opacity-100 bottom-[calc(100%+4px)] bg-surface border border-border text-[10px] font-medium px-2 py-1 rounded shadow-md whitespace-nowrap z-10 pointer-events-none">
                        Semana {w.number}: {w.examsCount} {w.examsCount === 1 ? 'examen' : 'exámenes'}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </div>

        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Plus, X, AlertOctagon } from 'lucide-react';
import { usePlannerStore } from '../store/usePlannerStore';
import type { WeekBlock, BlockCategory } from '../types';
import { cn, CAT_COLORS } from '../lib/utils';
import { Button } from '../components/ui/Button';
import { Modal } from '../components/ui/Modal';

const DAYS = ['Lunes', 'Martes', 'Miércoles', 'Jueves', 'Viernes', 'Sábado', 'Domingo'];
const HOURS = Array.from({ length: 17 }, (_, i) => i + 7);

// ─── Modal Form ─────────────────────────────────────────────────────────────────
const BlockForm: React.FC<{ initial: Partial<WeekBlock>, onSave: (d: Omit<WeekBlock, 'id'>) => void, onCancel: () => void }> = ({ initial, onSave, onCancel }) => {
  const [f, setF] = useState({ 
    day: initial.day ?? 0, 
    startHour: initial.startHour ?? 8, 
    endHour: initial.endHour ?? 10, 
    category: (initial.category ?? 'estudio') as BlockCategory, 
    label: initial.label ?? '' 
  });

  const submit = (e: React.FormEvent) => {
    e.preventDefault();
    if (f.endHour <= f.startHour) return alert('La hora de fin debe ser posterior al inicio');
    onSave(f as any);
  };

  return (
    <form onSubmit={submit} className="flex flex-col gap-4">
      <div className="grid grid-cols-2 gap-3">
        <div>
          <label className="label mb-1.5 block">Día</label>
          <select className="input" value={f.day} onChange={e => setF({...f, day: Number(e.target.value) as WeekBlock['day']})}>
            {DAYS.map((d, i) => <option key={i} value={i}>{d}</option>)}
          </select>
        </div>
        <div>
          <label className="label mb-1.5 block">Categoría</label>
          <select className="input" value={f.category} onChange={e => setF({...f, category: e.target.value as BlockCategory})}>
            {Object.keys(CAT_COLORS).map(c => <option key={c} value={c}>{c}</option>)}
          </select>
        </div>
      </div>
      <div className="grid grid-cols-2 gap-3">
        <div>
          <label className="label mb-1.5 block">Inicio</label>
          <select className="input" value={f.startHour} onChange={e => setF({...f, startHour: Number(e.target.value)})}>
            {HOURS.map(h => <option key={h} value={h}>{h}:00</option>)}
          </select>
        </div>
        <div>
          <label className="label mb-1.5 block">Fin</label>
          <select className="input" value={f.endHour} onChange={e => setF({...f, endHour: Number(e.target.value)})}>
            {HOURS.filter(h => h > f.startHour).map(h => <option key={h} value={h}>{h}:00</option>)}
          </select>
        </div>
      </div>
      <div>
        <label className="label mb-1.5 block">Etiqueta</label>
        <input className="input" value={f.label} onChange={e=>setF({...f, label: e.target.value})} required placeholder="Ej: Laboratorio de Física" />
      </div>
      <div className="flex justify-end gap-2 mt-2">
        <Button type="button" variant="ghost" onClick={onCancel}>Cancelar</Button>
        <Button type="submit" variant="primary">Agendar</Button>
      </div>
    </form>
  );
};

// ─── Planner Page ──────────────────────────────────────────────────────────────
export const WeeklyPlanner: React.FC = () => {
  const { blocks, addBlock, deleteBlock } = usePlannerStore();
  const [modalOpen, setModalOpen] = useState(false);
  const [clickedCell, setClickedCell] = useState<{ day: number; hour: number } | null>(null);

  const load = blocks.filter(b => b.category === 'estudio' || b.category === 'facultad').reduce((a, b) => a + (b.endHour - b.startHour), 0);
  const overloaded = load > 40;
  const heavyOverload = load > 45;

  const handleCellClick = (d: number, h: number) => { setClickedCell({ day: d, hour: h }); setModalOpen(true); };
  const ROW_H = 48; // px

  return (
    <div className="max-w-7xl mx-auto h-full flex flex-col pb-4">
      <header className="mb-4 flex flex-col md:flex-row md:items-end justify-between gap-4 shrink-0">
        <div>
          <h1 className="text-2xl font-semibold tracking-tight text-text-primary mb-1">Planificador</h1>
        </div>
        <Button variant="primary" onClick={() => { setClickedCell(null); setModalOpen(true); }}>
          <Plus size={16} /> Nuevo Bloque
        </Button>
      </header>

      {/* Warning */}
      {load > 35 && (
        <motion.div initial={{ opacity: 0, y: -10 }} animate={{ opacity: 1, y: 0 }} 
          className={cn("px-4 py-3 rounded-card mb-4 flex items-center gap-3 border text-[13px] font-medium", 
             heavyOverload ? "bg-red/10 border-red/20 text-red" : "bg-amber/10 border-amber/20 text-amber")}>
          <AlertOctagon size={16} />
          <span>Atención: Llevas {load}h semanales de carga académica. {heavyOverload ? 'Considera priorizar descansos.' : 'Estás cerca del límite recomendado.'}</span>
        </motion.div>
      )}

      {/* Grid container */}
      <div className="flex-1 overflow-auto rounded-card border border-border bg-base w-full">
        <div className="min-w-[800px] flex text-text-muted text-[11px] font-semibold tracking-wide border-b border-border sticky top-0 bg-base/95 backdrop-blur z-20">
          <div className="w-12 shrink-0 border-r border-border" />
          {DAYS.map(d => (
            <div key={d} className="flex-1 py-3 text-center uppercase tracking-widest">{d.slice(0,3)}</div>
          ))}
        </div>

        <div className="min-w-[800px] flex relative bg-surface">
          {/* Time axis */}
          <div className="w-12 shrink-0 flex flex-col border-r border-border bg-base z-10">
            {HOURS.map(h => (
              <div key={h} style={{ height: ROW_H }} className="relative border-b border-border/30">
                <span className="absolute -top-2.5 right-2 text-[10px] text-text-faint">{h}:00</span>
              </div>
            ))}
          </div>

          {/* Days */}
          {DAYS.map((_, dayIdx) => (
            <div key={dayIdx} className="flex-1 relative border-r border-border/30 last:border-r-0">
              {HOURS.map((h, i) => (
                <div key={h} style={{ height: ROW_H, top: i * ROW_H }} 
                     className="absolute w-full border-b border-border/10 cursor-pointer hover:bg-[rgba(255,255,255,0.02)] transition-colors"
                     onClick={() => handleCellClick(dayIdx, h)} />
              ))}

              {/* Blocks */}
              <AnimatePresence>
                {blocks.filter(b => b.day === dayIdx).map(b => {
                  const top = (b.startHour - 7) * ROW_H;
                  const height = (b.endHour - b.startHour) * ROW_H;
                  const color = CAT_COLORS[b.category];
                  return (
                    <motion.div
                      key={b.id}
                      initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0, scale: 0.9 }}
                      className="absolute left-[2px] right-[2px] rounded-[6px] overflow-hidden group shadow-md"
                      style={{ top: top + 1, height: height - 2, borderLeft: `3px solid ${color}`, backgroundColor: 'rgba(23, 19, 11, 0.95)', borderTop: '0.5px solid #2e2010', borderRight: '0.5px solid #2e2010', borderBottom: '0.5px solid #2e2010' }}
                    >
                      <div className="absolute top-0 right-0 w-8 h-8 opacity-0 group-hover:opacity-100 bg-gradient-to-bl from-red/80 to-transparent transition-opacity flex items-start justify-end p-1 z-10 z-10 cursor-pointer" onClick={() => deleteBlock(b.id)}>
                        <X size={12} className="text-white drop-shadow" />
                      </div>
                      <div className="w-full h-full p-[6px] flex flex-col relative z-0">
                        <span className="text-[11px] font-semibold leading-tight line-clamp-2" style={{ color }}>{b.label}</span>
                        {height > 50 && <span className="text-[9px] text-text-muted mt-0.5">{b.startHour}h — {b.endHour}h</span>}
                      </div>
                    </motion.div>
                  );
                })}
              </AnimatePresence>
            </div>
          ))}
        </div>
      </div>

      <Modal open={modalOpen} onClose={() => setModalOpen(false)} title="Agendar Bloque" size="sm">
        <BlockForm 
          initial={clickedCell ? { day: clickedCell.day as WeekBlock['day'], startHour: clickedCell.hour, endHour: Math.min(clickedCell.hour + 2, 23) } : {}}
          onSave={d => { addBlock(d); setModalOpen(false); }}
          onCancel={() => setModalOpen(false)}
        />
      </Modal>
    </div>
  );
};

import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import type { Exam, SubjectStatus } from '../types';
import { SEED_EXAMS } from '../lib/seed';

interface ExamFilters {
  subject: string;
  status: string;
  type: string;
}

interface ExamStore {
  exams: Exam[];
  subjectStatuses: SubjectStatus[];
  filters: ExamFilters;
  addExam: (exam: Omit<Exam, 'id'>) => void;
  updateExam: (id: string, updates: Partial<Exam>) => void;
  deleteExam: (id: string) => void;
  setFilters: (filters: Partial<ExamFilters>) => void;
  updateSubjectStatus: (subject: string, updates: Partial<SubjectStatus>) => void;
  recalculateStatuses: () => void;
}

const calculateSubjectStatuses = (exams: Exam[], currentStatuses: SubjectStatus[]): SubjectStatus[] => {
  const subjects = new Set(exams.map(e => e.subject));
  const newStatuses = [...currentStatuses];

  // Add missing subjects
  subjects.forEach(subject => {
    if (!newStatuses.find(s => s.subject === subject)) {
      newStatuses.push({
        subject,
        maxFails: 2,
        currentFails: 0,
        hasLost: false,
      });
    }
  });

  // Calculate fails and hasLost for all statuses
  return newStatuses.map(status => {
    const fails = exams.filter(e => e.subject === status.subject && (e.status === 'desaprobado' || e.status === 'ausente')).length;
    return {
      ...status,
      currentFails: fails,
      hasLost: fails >= status.maxFails,
    };
  });
};

export const useExamStore = create<ExamStore>()(
  persist(
    (set, get) => ({
      exams: [], // will be seeded manually if empty
      subjectStatuses: [],
      filters: { subject: '', status: '', type: '' },
      addExam: (exam) =>
        set((state) => {
          const newExams = [...state.exams, { ...exam, id: crypto.randomUUID() }];
          return {
            exams: newExams,
            subjectStatuses: calculateSubjectStatuses(newExams, state.subjectStatuses),
          };
        }),
      updateExam: (id, updates) =>
        set((state) => {
          const newExams = state.exams.map((e) => (e.id === id ? { ...e, ...updates } : e));
          return {
            exams: newExams,
            subjectStatuses: calculateSubjectStatuses(newExams, state.subjectStatuses),
          };
        }),
      deleteExam: (id) =>
        set((state) => {
          const newExams = state.exams.filter((e) => e.id !== id);
          return {
            exams: newExams,
            subjectStatuses: calculateSubjectStatuses(newExams, state.subjectStatuses),
          };
        }),
      setFilters: (f) =>
        set((state) => ({ filters: { ...state.filters, ...f } })),
      updateSubjectStatus: (subject, updates) =>
        set((state) => {
          const statuses = state.subjectStatuses.map(s => s.subject === subject ? { ...s, ...updates } : s);
          return {
            subjectStatuses: calculateSubjectStatuses(state.exams, statuses),
          };
        }),
      recalculateStatuses: () =>
        set((state) => ({
          subjectStatuses: calculateSubjectStatuses(state.exams, state.subjectStatuses),
        })),
    }),
    { 
      name: 'fos-exams',
      onRehydrateStorage: () => (state) => {
        if (state) {
          state.recalculateStatuses(); // Ensure calculated fields are up to date on load
        }
      }
    }
  )
);

export function useFilteredExams() {
  const { exams, filters } = useExamStore();
  return exams.filter((e) => {
    if (filters.subject && e.subject !== filters.subject) return false;
    if (filters.status && e.status !== filters.status) return false;
    if (filters.type && e.type !== filters.type) return false;
    return true;
  });
}
